package main

import (
	"strings"
)

func lcp(a, b string) int {
	minLen := len(a)
	if len(b) < minLen {
		minLen = len(b)
	}
	for i := 0; i < minLen; i++ {
		if a[i] != b[i] {
			return i
		}
	}
	return minLen
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

func solve(words []string) []int64 {
	n := len(words)
	if n == 0 {
		return []int64{}
	}
	if n == 1 {
		return []int64{0}
	}

	adj_lcp := make([]int, n-1)
	for i := 0; i < n-1; i++ {
		adj_lcp[i] = lcp(words[i], words[i+1])
	}

	left_max := make([]int, n)
	left_max[0] = 0
	for i := 1; i < n; i++ {
		left_max[i] = max(left_max[i-1], adj_lcp[i-1])
	}

	right_max := make([]int, n)
	right_max[n-1] = 0
	for i := n - 2; i >= 0; i-- {
		right_max[i] = max(adj_lcp[i], right_max[i+1])
	}

	result := make([]int64, n)
	for i := 0; i < n; i++ {
		if i == 0 {
			if n == 1 {
				result[i] = 0
			} else {
				result[i] = int64(right_max[1])
			}
		} else if i == n-1 {
			if n == 1 {
				result[i] = 0
			} else {
				result[i] = int64(left_max[n-2])
			}
		} else {
			max_left := left_max[i-1]
			max_right := right_max[i+1]
			new_lcp := lcp(words[i-1], words[i+1])
			current_max := max(max_left, max_right)
			if new_lcp > current_max {
				current_max = new_lcp
			}
			result[i] = int64(current_max)
		}
	}
	return result
}
